{"content": "*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  min-height: 100vh;
  background: linear-gradient(135deg, #0f2b4a 0%, #2d6fc4 50%, #6bb5e8 100%);
  display: flex;
  justify-content: center;
  align-items: flex-start;
  padding: 2rem 1rem;
  color: #333;
}

.container {
  width: 100%;
  max-width: 480px;
  background: rgba(255, 255, 255, 0.97);
  border-radius: 24px;
  padding: 2rem;
  box-shadow: 0 25px 60px rgba(0, 0, 0, 0.2);
  margin-top: 1rem;
}

/* Header */
header {
  text-align: center;
  margin-bottom: 1.5rem;
}

header h1 {
  font-size: 1.8rem;
  color: #0f2b4a;
  margin-bottom: 0.25rem;
  font-weight: 700;
}

.header-icon {
  margin-right: 0.25rem;
}

.subtitle {
  font-size: 0.9rem;
  color: #777;
}

/* Search form */
.search-box {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.search-box input {
  flex: 1;
  padding: 0.8rem 1rem;
  border: 2px solid #e0e0e0;
  border-radius: 12px;
  font-size: 1rem;
  font-family: inherit;
  outline: none;
  transition: border-color 0.2s ease;
}

.search-box input:focus {
  border-color: #2d6fc4;
}

.search-box button {
  padding: 0.8rem 1.5rem;
  background: linear-gradient(135deg, #2d6fc4, #4a90d9);
  color: #fff;
  border: none;
  border-radius: 12px;
  font-size: 1rem;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: opacity 0.2s ease, transform 0.1s ease;
}

.search-box button:hover {
  opacity: 0.9;
}

.search-box button:active {
  transform: scale(0.97);
}

/* Preset city buttons */
.preset-cities {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  justify-content: center;
  margin-bottom: 1.5rem;
}

.preset-btn {
  padding: 0.4rem 1.1rem;
  background: #eef3fa;
  color: #0f2b4a;
  border: 1px solid #d0dce8;
  border-radius: 20px;
  font-size: 0.85rem;
  font-family: inherit;
  cursor: pointer;
  transition: background 0.2s ease, transform 0.1s ease;
}

.preset-btn:hover {
  background: #dce8f5;
}

