'use strict';

const http = require('http');
const { spawn } = require('child_process');
const path = require('path');

const PORT = 3001;
const BASE = `http://localhost:${PORT}`;
const SERVER_CMD = 'node';
const SERVER_ARGS = ['server.js'];
const SERVER_DIR = path.resolve(__dirname, '..');

let pass = 0;
let fail = 0;
let serverProcess = null;

function assert(label, condition, detail) {
  if (condition) {
    pass++;
    console.log(`  ✅ PASS: ${label}`);
  } else {
    fail++;
    console.log(`  ❌ FAIL: ${label}`);
    if (detail) console.log(`       ${detail}`);
  }
}

function fetch(urlPath) {
  return new Promise((resolve, reject) => {
    http.get(`${BASE}${urlPath}`, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          resolve({ status: res.statusCode, headers: res.headers, body: data, json: () => JSON.parse(data) });
        } catch (e) {
          resolve({ status: res.statusCode, headers: res.headers, body: data, json: () => ({ parseError: e.message }) });
        }
      });
    }).on('error', (err) => reject(err));
  });
}

function waitForServer(url, retries = 10, delay = 500) {
  return new Promise((resolve, reject) => {
    function attempt(n) {
      http.get(url, (res) => {
        res.resume();
        resolve();
      }).on('error', () => {
        if (n <= 0) reject(new Error('Server did not start'));
        else setTimeout(() => attempt(n - 1), delay);
      });
    }
    attempt(retries);
  });
}

async function runTests() {
  console.log('\n🌤️  Weather App Integration Tests\n');
  console.log('Starting server...');

  return new Promise((resolve, reject) => {
    serverProcess = spawn(SERVER_CMD, SERVER_ARGS, {
      cwd: SERVER_DIR,
      env: { ...process.env, PORT: String(PORT) },
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    let serverOutput = '';
    serverProcess.stdout.on('data', (d) => { serverOutput += d.toString(); });
    serverProcess.stderr.on('data', (d) => { serverOutput += d.toString(); });

    waitForServer(`http://localhost:${PORT}/health`, 15, 500)
      .then(async () => {
        console.log(`  Server running on port ${PORT}\n`);

        // 1. Health check
        console.log('[Health]');
        const health = await fetch('/health');
        assert('GET /health returns 200', health.status === 200, `Got ${health.status}`);
        assert('GET /health returns ok', health.json().status === 'ok', JSON.stringify(health.json()));

        // 2. Weather - valid city
        console.log('\n[Weather - Valid City]');
        const london = await fetch('/api/weather?city=London');
        assert('GET /api/weather?city=London returns 200', london.status === 200, `Got ${london.status}`);
        const lj = london.json();
        assert('Response has city field', lj.city === 'London', `Got ${lj.city}`);
        assert('Response has temperature', typeof lj.temperature === 'number', `Got ${lj.temperature}`);
        assert('Response has humidity', typeof lj.humidity === 'number', `Got ${lj.humidity}`);
        assert('Response has wind_speed', typeof lj.wind_speed === 'number', `Got ${lj.wind_speed}`);
        assert('Response has condition string', typeof lj.condition === 'string' && lj.condition.length > 0);
        assert('Response has emoji', typeof lj.emoji === 'string' && lj.emoji.length > 0);

        // 3. Weather - another city
        console.log('\n[Weather - Another City]');
        const tokyo = await fetch('/api/weather?city=Tokyo');
        assert('GET /api/weather?city=Tokyo returns 200', tokyo.status === 200, `Got ${tokyo.status}`);
        assert('Tokyo city is "Tokyo"', tokyo.json().city === 'Tokyo');

        // 4. Weather - empty city
        console.log('\n[Weather - Edge Cases]');
        const empty = await fetch('/api/weather?city=');
        assert('Empty city returns 400', empty.status === 400, `Got ${empty.status}`);
        assert('Empty city has error message', empty.json().error !== undefined);

        // 5. Weather - no city parameter
        const noParam = await fetch('/api/weather');
        assert('No city param returns 400', noParam.status === 400, `Got ${noParam.status}`);

        // 6. Weather - nonexistent city
        const invalid = await fetch('/api/weather?city=DoesNotExist12345');
        assert('Invalid city returns 404', invalid.status === 404, `Got ${invalid.status}`);
        assert('Invalid city has error', invalid.json().error && invalid.json().error.includes('not found'));

        // 7. Static files
        console.log('\n[Static Files]');
        const index = await fetch('/');
        assert('GET / returns 200', index.status === 200, `Got ${index.status}`);
        assert('HTML contains Weather App title', index.body.includes('<title>Weather App</title>'));

        const css = await fetch('/style.css');
        assert('GET /style.css returns 200', css.status === 200, `Got ${css.status}`);
        assert('CSS contains body styling', css.body.includes('body'));

        const js = await fetch('/app.js');
        assert('GET /app.js returns 200', js.status === 200, `Got ${js.status}`);
        assert('JS contains fetchWeather function', js.body.includes('fetchWeather'));

        // Summary
        console.log(`\n━━━━━━━━━━━━━━━━━━━━━━━━━━━`);
        console.log(`Results: ${pass} passed, ${fail} failed out of ${pass + fail} tests\n`);

        resolve(fail === 0);
      })
      .catch((err) => {
        console.error(`Failed to start server: ${err.message}`);
        console.error(`Server output: ${serverOutput}`);
        resolve(false);
      });
  });
}

runTests().then((ok) => {
  if (serverProcess) {
    serverProcess.kill();
    setTimeout(() => process.exit(ok ? 0 : 1), 200);
  } else {
    process.exit(ok ? 0 : 1);
  }
});
